const t={klipperscreenStudio:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Безопасно редактируйте конфигурацию сенсорного экрана KlipperScreen вашего принтера и перезапускайте KlipperScreen для применения. Перед каждым сохранением создаётся резервная копия."}},help:{title:{t:0,b:{t:2,i:[{t:3}],s:"Как это работает"}},body:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen.conf управляет сенсорным экраном, подключённым к принтеру — тема, язык, меню и параметры отображения. Этот редактор читает и пишет файл тем же безопасным путём, что и Редактор конфигурации."}},step1:{t:0,b:{t:2,i:[{t:3}],s:"Отредактируйте текст конфигурации ниже (или оставьте как есть)."}},step2:{t:0,b:{t:2,i:[{t:3}],s:"Сохраните — файл сначала резервируется, а сохранение отклоняется, пока принтер занят."}},step3:{t:0,b:{t:2,i:[{t:3}],s:"Перезапустите KlipperScreen, чтобы применить изменение на физическом экране."}},lfNote:{t:0,b:{t:2,i:[{t:3}],s:"Строки используют окончания UNIX (LF), применяемые автоматически при сохранении."}}},status:{checking:{t:0,b:{t:2,i:[{t:3}],s:"Поиск KlipperScreen…"}},absent:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen не обнаружен на этом принтере (нет KlipperScreen.conf, и не сообщён Moonraker). Установите KlipperScreen, чтобы использовать этот инструмент."}},present:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen обнаружен"}},theme:{t:0,b:{t:2,i:[{t:3}],s:"Тема"}},language:{t:0,b:{t:2,i:[{t:3}],s:"Язык"}},notRestartable:{t:0,b:{t:2,i:[{t:3}],s:"Moonraker не может перезапустить KlipperScreen автоматически — перезапустите его вручную после сохранения."}}},editor:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Чтение KlipperScreen.conf…"}},reload:{t:0,b:{t:2,i:[{t:3}],s:"Перезагрузить"}},save:{t:0,b:{t:2,i:[{t:3}],s:"Сохранить конфиг"}},saving:{t:0,b:{t:2,i:[{t:3}],s:"Сохранение…"}},saved:{t:0,b:{t:2,i:[{t:3}],s:"Сохранено (с резервной копией)"}},unsaved:{t:0,b:{t:2,i:[{t:3}],s:"Несохранённые изменения"}}},save:{busy:{t:0,b:{t:2,i:[{t:3}],s:"Отклонено, пока принтер занят — повторите, когда он свободен."}},stale:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen.conf изменился на диске с момента загрузки (вероятно, отредактирован на экране). Перезагрузите перед сохранением, чтобы не перезаписать это изменение."}}},restart:{button:{t:0,b:{t:2,i:[{t:3}],s:"Перезапустить KlipperScreen"}},restarting:{t:0,b:{t:2,i:[{t:3}],s:"Перезапуск…"}},done:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen перезапускается — экран скоро обновится."}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"Перезапустить KlipperScreen?"}},confirmBody:{t:0,b:{t:2,i:[{t:3}],s:"Это перезапустит службу сенсорного экрана для применения изменений. Это не повлияет на активную печать, но экран погаснет на несколько секунд."}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Перезапустить"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Отмена"}}}}};export{t as default};
